import{_ as t,o,c as a,a2 as n}from"./chunks/framework.B72_uj9U.js";const m=JSON.parse('{"title":"ForgeCode ‚Äî Benchmark Results & Analysis","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/forgecode/benchmarks.md","filePath":"research/agents/forgecode/benchmarks.md"}'),i={name:"research/agents/forgecode/benchmarks.md"};function r(s,e,l,d,c,h){return o(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="forgecode-‚Äî-benchmark-results-analysis" tabindex="-1">ForgeCode ‚Äî Benchmark Results &amp; Analysis <a class="header-anchor" href="#forgecode-‚Äî-benchmark-results-analysis" aria-label="Permalink to &quot;ForgeCode ‚Äî Benchmark Results &amp; Analysis&quot;">‚Äã</a></h1><h2 id="terminal-bench-2-0-results" tabindex="-1">Terminal-Bench 2.0 Results <a class="header-anchor" href="#terminal-bench-2-0-results" aria-label="Permalink to &quot;Terminal-Bench 2.0 Results&quot;">‚Äã</a></h2><p>Terminal-Bench (TermBench) 2.0 is a realistic evaluation suite where agents receive coding tasks in a sandboxed terminal environment and must complete them autonomously under strict time constraints. It tests codebase navigation, problem decomposition, tool calling, and task completion.</p><h3 id="current-leaderboard-positions" tabindex="-1">Current Leaderboard Positions <a class="header-anchor" href="#current-leaderboard-positions" aria-label="Permalink to &quot;Current Leaderboard Positions&quot;">‚Äã</a></h3><table tabindex="0"><thead><tr><th>Rank</th><th>Agent + Model</th><th>Completion %</th></tr></thead><tbody><tr><td>#1</td><td>ForgeCode + Claude Opus 4.6</td><td><strong>81.8%</strong></td></tr><tr><td>#1</td><td>ForgeCode + GPT 5.4</td><td><strong>81.8%</strong></td></tr><tr><td>‚Äî</td><td>ForgeCode + Gemini 3.1 Pro Preview</td><td><strong>78.4%</strong></td></tr><tr><td>‚Äî</td><td>Warp</td><td>61.2%</td></tr><tr><td>‚Äî</td><td>Claude Code</td><td>58%</td></tr><tr><td>‚Äî</td><td>Open Code</td><td>51.7%</td></tr></tbody></table><p>Source: <a href="https://www.tbench.ai/leaderboard/terminal-bench/2.0" target="_blank" rel="noreferrer">tbench.ai leaderboard</a> and ForgeCode landing page.</p><h3 id="model-vendor-comparison" tabindex="-1">Model-Vendor Comparison <a class="header-anchor" href="#model-vendor-comparison" aria-label="Permalink to &quot;Model-Vendor Comparison&quot;">‚Äã</a></h3><p>Google reports Gemini 3.1 Pro Preview scoring 68.5% on TermBench when run natively. ForgeCode ran the same model and scored 78.4% ‚Äî a <strong>10 percentage point improvement</strong> from the same weights in a better runtime harness.</p><h2 id="the-journey-25-‚Üí-78-4-‚Üí-81-8" tabindex="-1">The Journey: 25% ‚Üí 78.4% ‚Üí 81.8% <a class="header-anchor" href="#the-journey-25-‚Üí-78-4-‚Üí-81-8" aria-label="Permalink to &quot;The Journey: 25% ‚Üí 78.4% ‚Üí 81.8%&quot;">‚Äã</a></h2><p>ForgeCode&#39;s benchmark improvement was documented in two detailed blog posts. The progression reveals how specific failure-mode fixes compound into large gains.</p><h3 id="phase-1-baseline-‚Äî-25" tabindex="-1">Phase 1: Baseline ‚Äî ~25% <a class="header-anchor" href="#phase-1-baseline-‚Äî-25" aria-label="Permalink to &quot;Phase 1: Baseline ‚Äî ~25%&quot;">‚Äã</a></h3><p>The initial run used ForgeCode&#39;s interactive-first runtime. The agent asked clarifying questions (no user to answer in a benchmark), hesitated before committing, and used conversational patterns unsuited to autonomous execution.</p><p><strong>Root cause</strong>: The agent was built for interactive use, not autonomous execution.</p><h3 id="phase-2-stabilization-‚Äî-38" tabindex="-1">Phase 2: Stabilization ‚Äî ~38% <a class="header-anchor" href="#phase-2-stabilization-‚Äî-38" aria-label="Permalink to &quot;Phase 2: Stabilization ‚Äî ~38%&quot;">‚Äã</a></h3><p><strong>Fixes applied</strong>:</p><ul><li><strong>Non-Interactive Mode</strong>: System prompt rewritten to prohibit clarification and hedging</li><li><strong>Tool-call naming</strong>: Renamed arguments to training-data-aligned names (e.g., <code>old_string</code>/<code>new_string</code>)</li><li><strong>Per-tool micro-evaluations</strong>: Built targeted evals that isolate tool-call failures by class (wrong tool, wrong args, wrong sequence) per model</li></ul><p><strong>Key insight</strong>: Tool misuse was one of the top two failure classes. Models pattern-match tool names against training data priors ‚Äî alignment with those priors reduces errors.</p><h3 id="phase-3-planning-control-‚Äî-66" tabindex="-1">Phase 3: Planning Control ‚Äî 66% <a class="header-anchor" href="#phase-3-planning-control-‚Äî-66" aria-label="Permalink to &quot;Phase 3: Planning Control ‚Äî 66%&quot;">‚Äã</a></h3><p><strong>Fixes applied</strong>:</p><ul><li><strong><code>todo_write</code> enforcement</strong>: Made task decomposition tracking mandatory, not optional</li><li><strong>Low-level evals</strong>: Built assertions that check whether <code>todo_write</code> is called for multi-step tasks and items are updated as the agent progresses</li></ul><p><strong>Key insight</strong>: Optional tools get deprioritized under pressure. When an agent is deep in a complex problem, it takes the path of least resistance ‚Äî the next tool call that seems relevant, not the one that maintains planning state. Enforcement, not suggestion, was required.</p><h3 id="phase-4-speed-architecture-‚Äî-78-4-sota-with-gemini-3-1-pro" tabindex="-1">Phase 4: Speed Architecture ‚Äî 78.4% (SOTA with Gemini 3.1 Pro) <a class="header-anchor" href="#phase-4-speed-architecture-‚Äî-78-4-sota-with-gemini-3-1-pro" aria-label="Permalink to &quot;Phase 4: Speed Architecture ‚Äî 78.4% (SOTA with Gemini 3.1 Pro)&quot;">‚Äã</a></h3><p><strong>Fixes applied</strong>:</p><ul><li><strong>Sub-agent parallelization</strong>: Low-complexity work (file reads, pattern searches, routine edits) delegated to sub-agents with minimal thinking budget</li><li><strong>Progressive thinking policy</strong>: High thinking for first 10 messages (planning), low for messages 11+ (execution), high again for verification</li><li><strong>Skill routing</strong>: Dynamic skill loading matched to task profiles</li><li><strong>Semantic entry-point discovery</strong>: Context engine identifies starting files before the agent explores</li></ul><p><strong>Key insight</strong>: Intelligence without speed fails benchmarks. TermBench has strict wall-clock time limits. A brilliant but slow agent times out just as definitively as a wrong one.</p><h3 id="phase-5-model-specific-tuning-‚Äî-81-8-sota-with-opus-4-6-gpt-5-4" tabindex="-1">Phase 5: Model-Specific Tuning ‚Äî 81.8% (SOTA with Opus 4.6 + GPT 5.4) <a class="header-anchor" href="#phase-5-model-specific-tuning-‚Äî-81-8-sota-with-opus-4-6-gpt-5-4" aria-label="Permalink to &quot;Phase 5: Model-Specific Tuning ‚Äî 81.8% (SOTA with Opus 4.6 + GPT 5.4)&quot;">‚Äã</a></h3><p><strong>Fixes applied</strong>:</p><ul><li><strong>Schema field ordering</strong>: <code>required</code> before <code>properties</code> in JSON schemas (reduced GPT 5.4 malformed calls)</li><li><strong>Schema flattening</strong>: Flat schemas over nested to reduce structural confusion</li><li><strong>Explicit truncation signals</strong>: Plain-text reminders in tool result bodies for models that don&#39;t infer from metadata</li><li><strong>Enforced verification skill</strong>: Programmatic requirement to run a verification pass before task completion</li></ul><p><strong>Key insight</strong>: The two models fail in different places. Opus is more forgiving (tolerates messy schemas, infers from metadata). GPT 5.4 needs cleaner structure but reaches the same score with model-appropriate runtime tuning. The headline isn&#39;t &quot;model X beat model Y&quot; ‚Äî it&#39;s &quot;runtime version N learned how to stop triggering model X&#39;s failure modes.&quot;</p><h2 id="improvement-summary" tabindex="-1">Improvement Summary <a class="header-anchor" href="#improvement-summary" aria-label="Permalink to &quot;Improvement Summary&quot;">‚Äã</a></h2><table tabindex="0"><thead><tr><th>Phase</th><th>Change</th><th>Pass Rate</th></tr></thead><tbody><tr><td>Baseline</td><td>Interactive-first runtime</td><td>~25%</td></tr><tr><td>Stabilization</td><td>Non-Interactive mode + tool naming + micro-evals</td><td>~38%</td></tr><tr><td>Planning control</td><td><code>todo_write</code> enforcement</td><td>66%</td></tr><tr><td>Speed architecture</td><td>Sub-agent parallelization + progressive thinking + skill routing</td><td>78.4%</td></tr><tr><td>Model-specific tuning</td><td>Schema engineering + verification enforcement</td><td><strong>81.8%</strong></td></tr></tbody></table><h2 id="seven-failure-modes-identified" tabindex="-1">Seven Failure Modes Identified <a class="header-anchor" href="#seven-failure-modes-identified" aria-label="Permalink to &quot;Seven Failure Modes Identified&quot;">‚Äã</a></h2><p>The blog posts document seven specific failure modes discovered through TermBench:</p><ol><li><strong>Interactive behavior in autonomous context</strong> ‚Äî asking questions when no one is listening</li><li><strong>Tool-call misuse</strong> ‚Äî wrong tool, wrong args, wrong sequencing</li><li><strong>Training-data prior conflicts</strong> ‚Äî tool names/args that conflict with model expectations</li><li><strong>Entry-point discovery latency</strong> ‚Äî exploring the wrong part of the codebase</li><li><strong>Time budget exhaustion</strong> ‚Äî brilliant but meandering trajectories timing out</li><li><strong>Missing planning state</strong> ‚Äî forgetting sub-tasks without explicit tracking</li><li><strong>Premature completion</strong> ‚Äî declaring done before the task is actually complete</li></ol><p>Each failure mode was addressed with a targeted fix. No fix was a &quot;general quality improvement&quot; ‚Äî each was a specific intervention against a specific class.</p><h2 id="ongoing-evaluation" tabindex="-1">Ongoing Evaluation <a class="header-anchor" href="#ongoing-evaluation" aria-label="Permalink to &quot;Ongoing Evaluation&quot;">‚Äã</a></h2><p>ForgeCode now runs continuous evals in CI/CD that gate releases:</p><ul><li><strong>Per-tool reliability scores by model</strong> ‚Äî different models have different weak tools</li><li><strong><code>todo_write</code> compliance</strong> for decomposed tasks</li><li><strong>Entry-point discovery precision</strong></li><li><strong>Skill routing accuracy</strong></li><li><strong>Recovery rate</strong> after first tool-call error in a trajectory</li><li><strong>Time-efficiency curves</strong> under tight budgets</li></ul><p>These run in minutes and are derived from TermBench failure classes.</p><h2 id="meta-analysis-what-the-benchmarks-show" tabindex="-1">Meta-Analysis: What the Benchmarks Show <a class="header-anchor" href="#meta-analysis-what-the-benchmarks-show" aria-label="Permalink to &quot;Meta-Analysis: What the Benchmarks Show&quot;">‚Äã</a></h2><p>The ForgeCode benchmark story demonstrates three things:</p><ol><li><strong>Runtime engineering &gt; model capability</strong>: Same model weights, 10+ points higher in a better harness.</li><li><strong>Model comparison requires runtime-awareness</strong>: Evaluating models outside an agent runtime doesn&#39;t predict agent performance.</li><li><strong>Specific fixes beat general improvements</strong>: Each phase targeted a named failure class, not &quot;make the agent better.&quot;</li></ol><p>As their blog concludes: &quot;Don&#39;t run a benchmark to get a number. Run it to find out which part of your system is lying to you in production.&quot;</p>',43)])])}const u=t(i,[["render",r]]);export{m as __pageData,u as default};
